from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class ReviewLens(Enum):
    CORRECTNESS   = "correctness"    # does the change achieve its stated goal?
    SAFETY        = "safety"         # does it open any new harm vectors?
    SCOPE         = "scope"          # does it stay within the feature's product intent?
    EVAL_COVERAGE = "eval_coverage"  # are the new/changed behaviors covered by eval cases?


class ReviewVerdict(Enum):
    APPROVED       = "approved"
    APPROVED_WITH_NOTES = "approved_with_notes"  # minor notes; does not block merge
    CHANGES_REQUESTED  = "changes_requested"     # blocks merge
    VETOED         = "vetoed"         # safety lens only; hard block regardless of other approvals


@dataclass
class LensReview:
    reviewer: str
    lens: ReviewLens
    verdict: ReviewVerdict
    comments: list[str] = field(default_factory=list)
    inline_refs: list[str] = field(default_factory=list)  # "line 14: ...", "schema.tool_name: ..."

    @property
    def blocks_merge(self) -> bool:
        return self.verdict in (ReviewVerdict.CHANGES_REQUESTED, ReviewVerdict.VETOED)

    @property
    def is_veto(self) -> bool:
        return self.verdict == ReviewVerdict.VETOED


@dataclass
class EnsembleReview:
    pr_id: str
    change_description: str
    change_type: str    # "prompt", "tool_schema", "eval", "guardrail"
    reviews: list[LensReview] = field(default_factory=list)

    def add_review(self, review: LensReview) -> None:
        self.reviews.append(review)

    def is_merge_ready(self) -> bool:
        if any(r.is_veto for r in self.reviews):
            return False
        required_lenses = self._required_lenses()
        reviewed_lenses = {r.lens for r in self.reviews if not r.blocks_merge}
        return required_lenses.issubset(reviewed_lenses)

    def _required_lenses(self) -> set[ReviewLens]:
        if self.change_type == "eval":
            return {ReviewLens.EVAL_COVERAGE}
        if self.change_type == "tool_schema":
            return {ReviewLens.CORRECTNESS, ReviewLens.SAFETY, ReviewLens.SCOPE}
        # prompt or guardrail: all four lenses
        return {ReviewLens.CORRECTNESS, ReviewLens.SAFETY,
                ReviewLens.SCOPE, ReviewLens.EVAL_COVERAGE}

    def blockers(self) -> list[LensReview]:
        return [r for r in self.reviews if r.blocks_merge]

    def missing_lenses(self) -> set[ReviewLens]:
        submitted = {r.lens for r in self.reviews}
        return self._required_lenses() - submitted

    def summary(self) -> dict:
        return {
            "pr_id": self.pr_id,
            "change_type": self.change_type,
            "is_merge_ready": self.is_merge_ready(),
            "vetoed": any(r.is_veto for r in self.reviews),
            "blockers": [r.lens.value for r in self.blockers()],
            "missing_lenses": [l.value for l in self.missing_lenses()],
        }

from dataclasses import dataclass, field
from collections import deque


@dataclass
class ReviewerPool:
    members: list[str]     # all team members eligible to review
    lens_queue: dict[ReviewLens, deque] = field(default_factory=dict)

    def __post_init__(self) -> None:
        for lens in ReviewLens:
            self.lens_queue[lens] = deque(self.members)

    def assign_reviewer(self, lens: ReviewLens) -> str:
        """Assign the next reviewer for this lens (round-robin)."""        pool = self.lens_queue[lens]
        reviewer = pool.popleft()
        pool.append(reviewer)     # rotate to back
        return reviewer

    def assign_all_lenses(self, change_type: str) -> dict[ReviewLens, str]:
        """Assign reviewers for all required lenses for this change type."""        if change_type == "eval":
            lenses = [ReviewLens.EVAL_COVERAGE]
        elif change_type == "tool_schema":
            lenses = [ReviewLens.CORRECTNESS, ReviewLens.SAFETY, ReviewLens.SCOPE]
        else:
            lenses = list(ReviewLens)

        assignments: dict[ReviewLens, str] = {}
        for lens in lenses:
            reviewer = self.assign_reviewer(lens)
            # Ensure no one reviews the same PR on two lenses (only relevant with small teams)
            while reviewer in assignments.values() and len(self.members) >= len(lenses):
                reviewer = self.assign_reviewer(lens)
            assignments[lens] = reviewer

        return assignments


pool = ReviewerPool(members=["alice", "bob", "carol", "dave"])
print(pool.assign_all_lenses("prompt"))
# {CORRECTNESS: 'alice', SAFETY: 'bob', SCOPE: 'carol', EVAL_COVERAGE: 'dave'}

print(pool.assign_all_lenses("prompt"))
# {CORRECTNESS: 'bob', SAFETY: 'carol', SCOPE: 'dave', EVAL_COVERAGE: 'alice'}
# Each person rotates through all four lenses across successive PRs
